sp_widget.client_script:
function($scope, $http, spUtil) {
    var c = this;
    c.navTree = [];
    c.collapsed = false;
    c.loading = true;
    c.currentUrl = window.location.href;

    // Load navigation via GlideAjax
    function loadNavigation() {
        c.loading = true;
        var ga = new GlideAjax('x_146833_idpkiro.IDPNavigationEngine');
        ga.addParam('sysparm_name', 'ajaxGetNavigation');
        ga.getXMLAnswer(function(answer) {
            try {
                var tree = JSON.parse(answer);
                c.navTree = tree.taxonomies || [];
            } catch (e) {
                c.navTree = [];
            }
            c.loading = false;
            $scope.$apply();
        });
    }

    c.toggleCollapse = function() {
        c.collapsed = !c.collapsed;
        // Persist collapse state in session storage
        try {
            sessionStorage.setItem('idp_nav_collapsed', c.collapsed ? '1' : '0');
        } catch (e) {}
    };

    c.isActive = function(url) {
        return c.currentUrl.indexOf(url) !== -1;
    };

    // Restore collapse state
    try {
        c.collapsed = sessionStorage.getItem('idp_nav_collapsed') === '1';
    } catch (e) {}

    loadNavigation();
}

sp_widget.css:
.idp-side-nav {
  position: relative;
  height: 100%;
  background-color: var(--cds-ui-01, #f4f4f4);
  border-right: 1px solid var(--cds-ui-03, #e0e0e0);
  transition: width 110ms cubic-bezier(0.2, 0, 1, 0.9);
  overflow: hidden;
  width: 256px;
  min-height: 100vh;
}
.idp-side-nav.collapsed { width: 48px; }
.idp-nav-toggle {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding: 8px;
  border-bottom: 1px solid var(--cds-ui-03, #e0e0e0);
  cursor: pointer;
  background: transparent;
  border-left: none;
  border-right: none;
  border-top: none;
  width: 100%;
}
.idp-nav-toggle:hover { background-color: var(--cds-hover-ui, #e5e5e5); }
.idp-nav-group { margin-bottom: 4px; }
.idp-nav-group-header {
  display: flex;
  align-items: center;
  padding: 8px 16px;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--cds-text-02, #525252);
  text-transform: uppercase;
  letter-spacing: 0.32px;
  white-space: nowrap;
  overflow: hidden;
}
.idp-nav-group-icon {
  width: 16px;
  height: 16px;
  min-width: 16px;
  margin-right: 8px;
  fill: var(--cds-icon-02, #525252);
}
.idp-nav-group-label { overflow: hidden; white-space: nowrap; }
.idp-nav-item {
  display: flex;
  align-items: center;
  height: 32px;
  padding: 0 16px 0 32px;
  color: var(--cds-text-02, #525252);
  text-decoration: none;
  font-size: 0.875rem;
  white-space: nowrap;
  overflow: hidden;
  cursor: pointer;
}
.idp-nav-item:hover {
  background-color: var(--cds-hover-ui, #e5e5e5);
  color: var(--cds-text-01, #161616);
  text-decoration: none;
}
.idp-nav-item.active {
  background-color: var(--cds-selected-ui, #e0e0e0);
  color: var(--cds-text-01, #161616);
  font-weight: 600;
  border-left: 3px solid var(--cds-interactive-01, #0f62fe);
}
.idp-nav-item-icon {
  width: 16px;
  height: 16px;
  min-width: 16px;
  margin-right: 8px;
  fill: var(--cds-icon-02, #525252);
}
.idp-nav-item-label { overflow: hidden; white-space: nowrap; }
.collapsed .idp-nav-group-label,
.collapsed .idp-nav-item-label { display: none; }
.collapsed .idp-nav-item { padding: 0 16px; justify-content: center; }
.collapsed .idp-nav-group-header { padding: 8px; justify-content: center; }
.idp-nav-loading {
  padding: 16px;
  color: var(--cds-text-03, #a8a8a8);
  font-size: 0.875rem;
}

sp_widget.script:
(function() {
    // Server-side: nothing needed — navigation is built client-side via GlideAjax
    data.user_name = gs.getUserDisplayName();
})();
